test_fresh_install() {
    log "Test 1: Fresh install shows NotInstalled"
    OUTPUT=$("$RCH" state 2>&1)
    echo "$OUTPUT" | grep -qiE "not.?installed|needs.?setup" || fail "Should detect not installed"
    pass "Fresh install detection"
