        log "  Found $BACKUPS backup(s)"
    else
        log "  Note: Backup directory not found (may not be implemented)"
    fi

    pass "Backup creation"
}

# Run all tests
test_fresh_install
test_exit_codes
test_idempotent_init
test_lock_file
test_json_output
test_backup_creation

log "=== All State E2E tests passed ==="
